#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long R,B; scanf("%lld %lld", &R, &B);
        long long x = R < B ? R : B;
        long long ans = R + 2*B + 2*x;
        printf("%lld\n", ans);
    }
    return 0;
}

